```tsx web/breeze/components/PostActivationPage/components/PostActivationForm/SanityPostActivationForm.tsx
import Spinner from '@otovo/shared/components/LoadingScreens/Spinner';
import { useGlobalConfig } from '@otovo/shared/hooks/configContext';
import {
  Cloud$Interest,
  Cloud$PostActivationQuestion,
} from '@otovo/shared/types/cloudApi';
import {
  useSubmitUserFormInteraction,
  useSubmitUserFormQuestionInteraction,
} from '@otovo/shared/utils/userFormTrackingClient';
import { useEffect, useState } from 'react';
import { Card } from '../../../CalcPage/modals/ContactMeModal/CalcAcceptedCard';
import Questions from './Questions';
import {
  shouldIncludePartnerReportQuestion,
  updatePartnerText,
} from './partnerReportQuestionUtils';

type Props = {
  onComplete: () => void;
  interest: Cloud$Interest;
  questions: Array<Cloud$PostActivationQuestion>;
  formFetched: boolean;
};

const SanityPostActivationForm = ({
  interest,
  onComplete,
  questions,
  formFetched,
}: Props) => {
  const [activeStep, setActiveStep] = useState<number>(0);
  const [previousStep, setPreviousStep] = useState<number>(0);
  const [answered, setAnswered] = useState<boolean>(false);
  const [formStartTime, setFormStartTime] = useState<Date | null>(null);
  const [photosUploaded, setPhotosUploaded] = useState<boolean>(false);
  const [questionStartTime, setQuestionStartTime] = useState<Date | null>(null);
  const { BU_CONFIG } = useGlobalConfig();

  const { trigger: triggerSubmitFormInteraction } =
    useSubmitUserFormInteraction({
      interestId: interest?.id,
    });

  const { trigger: triggerSubmitQuestionInteraction } =
    useSubmitUserFormQuestionInteraction({
      interestId: interest?.id,
    });

  const filteredQuestions = questions
    .filter((question) => {
      return (
        question.name !== 'consent_to_share_data_with_partner' ||
        shouldIncludePartnerReportQuestion(interest?.affiliate, BU_CONFIG.slug)
      );
    })
    .map((question) => {
      if (question.name === 'consent_to_share_data_with_partner') {
        return updatePartnerText(question, interest?.affiliate, BU_CONFIG.slug);
      }
      return question;
    });

  const currentQuestion = filteredQuestions?.[activeStep];

  // Initialize form and question interactions
  useEffect(() => {
    if (formFetched && interest && !formStartTime) {
      const now = new Date();
      setFormStartTime(now);
      setQuestionStartTime(now);

      triggerSubmitFormInteraction({
        user_form_name: 'post_activation',
        form_completed: false,
        time_spent: 0,
      });

      triggerSubmitQuestionInteraction({
        answered: false,
        user_form_name: 'post_activation',
        question_name: currentQuestion?.name,
        photos_uploaded: false,
        time_spent: 0,
      });
    }
  }, [
    formFetched,
    interest,
    formStartTime,
    triggerSubmitFormInteraction,
    triggerSubmitQuestionInteraction,
    currentQuestion?.name,
  ]);

  // Log interactions when the active step changes
  useEffect(() => {
    if (!questionStartTime || !formStartTime || !currentQuestion) {
      return;
    }

    const logInteractions = async () => {
      const questionEndTime = new Date();
      const timeSpent =
        (questionEndTime.getTime() - questionStartTime.getTime()) / 1000;

      if (previousStep !== null) {
        // Log the previous question interaction
        triggerSubmitQuestionInteraction({
          answered,
          user_form_name: 'post_activation',
          question_name: filteredQuestions[previousStep]?.name,
          photos_uploaded: photosUploaded,
          time_spent: timeSpent,
        });
      }

      // Log the form interaction
      await triggerSubmitFormInteraction({
        user_form_name: 'post_activation',
        form_completed: false,
        time_spent: (new Date().getTime() - formStartTime.getTime()) / 1000,
      });

      // Initialize the current question interaction
      triggerSubmitQuestionInteraction({
        answered: false,
        user_form_name: 'post_activation',
        question_name: filteredQuestions[activeStep]?.name,
        photos_uploaded: false,
        time_spent: 0,
      });

      // Reset state for the new question
      setQuestionStartTime(new Date());
      setAnswered(false);
      setPhotosUploaded(false);
    };

    logInteractions();
    setPreviousStep(activeStep);

    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeStep]);

  const handleAnswerChange = async (isAnswered: boolean) => {
    setAnswered(isAnswered);
  };

  const handlePhotoUpload = async () => {
    setPhotosUploaded(true);
    setAnswered(true);
  };

  const handleFormComplete = async () => {
    if (questionStartTime && currentQuestion) {
      const questionEndTime = new Date();
      const timeSpent =
        (questionEndTime.getTime() - questionStartTime.getTime()) / 1000;

      triggerSubmitQuestionInteraction({
        answered,
        user_form_name: 'post_activation',
        question_name: currentQuestion.name,
        photos_uploaded: photosUploaded,
        time_spent: timeSpent,
      });
    }

    if (formStartTime && interest) {
      const endTime = new Date();
      const totalTimeSpent =
        (endTime.getTime() - formStartTime.getTime()) / 1000;

      triggerSubmitFormInteraction({
        user_form_name: 'post_activation',
        ended_at: endTime.toISOString(),
        form_completed: true,
        time_spent: totalTimeSpent,
      });
    }
    onComplete();
  };

  if (!formFetched || !interest) {
    return (
      <Card>
        <Spinner />
      </Card>
    );
  }

  return (
    <Questions
      interest={interest}
      questions={filteredQuestions}
      onComplete={handleFormComplete}
      onAnswerChange={handleAnswerChange}
      onPhotoUpload={handlePhotoUpload}
      setActiveStep={setActiveStep}
    />
  );
};

export default SanityPostActivationForm;
